function solve(nums, queries) {
  function countSetBits(x) {
    let count = 0;
    while (x) {
      x &= x - 1;
      count++;
    }
    return count;
  }

  function get_depth(x) {
    let depth = 0;
    let current = x;
    while (current !== 1) {
      current = countSetBits(current);
      depth++;
    }
    return depth;
  }

  class FenwickTree {
    constructor(size) {
      this.n = size;
      this.tree = new Array(this.n + 1).fill(0);
    }

    update(index, delta) {
      index += 1; // 1-based index
      while (index <= this.n) {
        this.tree[index] += delta;
        index += index & -index;
      }
    }

    query(index) {
      index += 1; // 1-based index
      let res = 0;
      while (index > 0) {
        res += this.tree[index];
        index -= index & -index;
      }
      return res;
    }

    rangeQuery(l, r) {
      return this.query(r) - this.query(l - 1);
    }
  }

  const n = nums.length;
  const maxDepth = 5;
  const ft = Array(maxDepth + 1).fill().map(() => new FenwickTree(n));
  const depths = new Array(n);

  for (let i = 0; i < n; i++) {
    depths[i] = get_depth(nums[i]);
  }

  for (let i = 0; i < n; i++) {
    const d = depths[i];
    if (d <= maxDepth) {
      ft[d].update(i, 1);
    }
  }

  const answer = [];
  for (const q of queries) {
    if (q[0] === 1) {
      const l = q[1];
      const r = q[2];
      const k = q[3];
      if (k > maxDepth) {
        answer.push(0);
        continue;
      }
      const count = ft[k].rangeQuery(l, r);
      answer.push(count);
    } else {
      const idx = q[1];
      const val = q[2];
      const oldVal = nums[idx];
      const oldDepth = depths[idx];
      if (oldDepth <= maxDepth) {
        ft[oldDepth].update(idx, -1);
      }
      nums[idx] = val;
      const newDepth = get_depth(val);
      if (newDepth <= maxDepth) {
        ft[newDepth].update(idx, 1);
      }
      depths[idx] = newDepth;
    }
  }

  return answer;
